INSERT INTO public.products (id, name, slug, description, price, old_price, images, is_featured, is_bestseller, stock_quantity, created_at, updated_at, product_type, active, config, config_status, config_version, config_updated_at, seo_title, seo_description, seo_keywords, meta_robots, canonical_url, og_title, og_description, og_image, content_sections, features, specifications, trust_badges, average_rating, review_count, featured_index, featured_image, fixed_price) VALUES ('ae6442ed-4ad2-4d55-92ec-0cfe77423452', 'Collage on Single Canvas', 'collage-on-single-canvas', 'Turn your photos into premium canvas prints with rich colors and sharp detail. This custom nine-photo collage is stretched on a sturdy frame and ready to hang, creating a beautiful décor piece or a meaningful gift designed to last.', 0.15, NULL, '{https://mhlmbpnyckrqyznwmbwo.supabase.co/storage/v1/object/public/photify/products/product-ae6442ed-4ad2-4d55-92ec-0cfe77423452-1776695394870-6mtcxrzik.png,https://mhlmbpnyckrqyznwmbwo.supabase.co/storage/v1/object/public/photify/products/product-ae6442ed-4ad2-4d55-92ec-0cfe77423452-1776695394867-ij5a56ra7.png,https://mhlmbpnyckrqyznwmbwo.supabase.co/storage/v1/object/public/photify/products/product-ae6442ed-4ad2-4d55-92ec-0cfe77423452-1776695394870-rh3m2sa2m.png,https://mhlmbpnyckrqyznwmbwo.supabase.co/storage/v1/object/public/photify/products/product-ae6442ed-4ad2-4d55-92ec-0cfe77423452-1777893532781-0e5j8l014.png}', true, false, 0, '2025-10-26 13:21:15.02018+00', '2026-05-04 11:26:46.737313+00', 'canvas', true, '{"version": 26, "sizePrices": {"35e98ad2-ca11-4641-be0a-169d019b23e1": 29.66, "37cbcaf0-d804-4776-ad68-2feba10f3938": 29.65, "52f8a8a4-84a3-4d15-9f5b-5b10da562090": 39.6, "5ce8164d-0911-4d05-9245-bc9b172295b5": 50.5, "5e0946c2-0431-489e-8e0f-cb0e244428e3": 31.82, "892a565d-0a86-4155-b3b5-90f2dcb226b1": 25.78, "908c2f8f-64bd-4059-a01a-921a7afbb715": 38.74, "b8d3468e-283a-4667-86e1-0f8bedfab78e": 50.4, "b909d248-018c-4776-b271-4b1f540fdd74": 38.74, "d7a17d53-ac6f-4157-85b2-13a16d469c5d": 35.5}, "allowedSizes": ["b8d3468e-283a-4667-86e1-0f8bedfab78e", "b909d248-018c-4776-b271-4b1f540fdd74", "35e98ad2-ca11-4641-be0a-169d019b23e1", "908c2f8f-64bd-4059-a01a-921a7afbb715", "5ce8164d-0911-4d05-9245-bc9b172295b5", "52f8a8a4-84a3-4d15-9f5b-5b10da562090", "5e0946c2-0431-489e-8e0f-cb0e244428e3", "892a565d-0a86-4155-b3b5-90f2dcb226b1", "d7a17d53-ac6f-4157-85b2-13a16d469c5d", "37cbcaf0-d804-4776-ad68-2feba10f3938"], "allowedRatios": ["352eec85-52e8-455d-9b79-ea3e2351f894", "672aee1b-8d97-4b2f-a122-e0ca5cdfb7f3", "d5f3c059-03e3-4ef3-afd8-b4d13315c60c"], "configurerType": "photo-collage-creator"}', 'active', 26, '2026-05-04 11:26:46.666+00', 'Collage Print on Single Canvas', E'Your Story, Beautifully Framed\nTurn your favorite photos into a premium 9-panel canvas print featuring rich colors and razor-sharp detail. Whether it''s a collection of family milestones, travel adventures, or candid everyday joys, this collage layout brings your best memories together in one stunning display.\n\nProduct Highlights:\nVibrant Quality: Printed with archival-grade inks for deep blacks and brilliant hues that won''t fade over time.\n\nBuilt to Last: Hand-stretched over a sturdy, warp-resistant frame for a professional gallery look.\n\nReady to Hang: Comes fully assembled with pre-installed hardware—just find the perfect spot on your wall.\n\nThe Perfect Gift: A meaningful, personalized centerpiece for your home or a thoughtful gift that will be cherished for a lifetime.\n\nPreserve what matters. Order your custom collage today.', '{canvas,collage,photify}', 'index,follow', '', '', '', '', '[]', '[{"icon": "check", "text": "Ready to Hang"}, {"icon": "sparkles", "text": "Real-life colours "}, {"icon": "zap", "text": "Super simple to create"}, {"icon": "badge-check", "text": "High-end quality"}]', '[{"label": "Product Type", "value": "Custom Photo Canvas Print"}, {"label": "Finish", "value": "Canvas Matt"}, {"label": "Frame Thickness", "value": "2 Inches"}, {"label": "Mounting", "value": "Ready to Hang"}, {"label": "Orientation", "value": "Square, Portrait, Landscape"}, {"label": "Usage", "value": "Home, Office, Gifts"}]', '[]', 4.6, 312, 2, 'https://mhlmbpnyckrqyznwmbwo.supabase.co/storage/v1/object/public/photify/featured-products/featured-ae6442ed-4ad2-4d55-92ec-0cfe77423452-1776697356905.jpg', 74.99) ON CONFLICT (id) DO NOTHING;
