-7765cfd948a8", "5e0946c2-0431-489e-8e0f-cb0e244428e3", "52f8a8a4-84a3-4d15-9f5b-5b10da562090", "37cbcaf0-d804-4776-ad68-2feba10f3938", "b909d248-018c-4776-b271-4b1f540fdd74", "b8d3468e-283a-4667-86e1-0f8bedfab78e", "892a565d-0a86-4155-b3b5-90f2dcb226b1", "d7a17d53-ac6f-4157-85b2-13a16d469c5d"], "allowedRatios": ["ed36b158-80c9-4b92-ba96-269ae5b222b0", "d5f3c059-03e3-4ef3-afd8-b4d13315c60c", "352eec85-52e8-455d-9b79-ea3e2351f894"], "configurerType": "multi-canvas-wall", "roomBackgrounds": [{"id": "room-1762372114279", "name": "Hahaha", "imageUrl": "https://mhlmbpnyckrqyznwmbwo.supabase.co/storage/v1/object/public/photify/room-backgrounds/room-bg-1762372113645.png", "isActive": true}]}', 'active', 14, '2026-05-07 20:07:34.129+00', '', E'Turn your favourite moments into a striking centrepiece with our 3 Panel Canvas Wall Art — designed to bring depth, emotion, and modern style into any space.\n\nEach set includes three perfectly aligned vertical panels (10" x 20" each), creating a balanced 1:1 overall layout with elegant 1:2 individual canvases. This format naturally draws the eye across the artwork, making it ideal for storytelling images like family portraits, travel memories, or cinematic landscapes.\n\nCrafted using premium gallery-wrapped canvas, every panel is stretched over a durable wooden frame, delivering a clean, frameless edge that feels contemporary and ready to hang straight out of the box.\n\nWhether displayed in a living room, hallway, or kitchen feature wall, this multi-panel design adds dimension and sophistication without overwhelming the space. The spacing between panels creates a subtle visual rhythm, giving your wall a curated, designer look.', '{canvas,3panelcanvas,photify}', 'index,follow', '', '', '', '', '[]', '[]', '[]', '[]', 4.7, 78, 4, 'https://mhlmbpnyckrqyznwmbwo.supabase.co/storage/v1/object/public/photify/featured-products/featured-62bf2021-be35-418f-b498-1587cf23d10f-1778183512280.jpg', 80.00) ON CONFLICT (id) DO NOTHING;
