8e": 50.4, "b909d248-018c-4776-b271-4b1f540fdd74": 38.74, "b9afd4c7-52be-4aaa-b13b-00bc21011cf7": 28.8, "b9df7747-36c8-4bf6-bb13-7765cfd948a8": 32.5, "c5fcb00a-6eb4-4d4c-859a-4a3784de5c9d": 28.8, "d7a17d53-ac6f-4157-85b2-13a16d469c5d": 35.5, "dcf6129b-1983-4a3e-8bf7-e69fd5b31fa4": 32.5}, "allowedSizes": ["7700c0ca-2514-4c74-8294-c20361eb02ee", "35e98ad2-ca11-4641-be0a-169d019b23e1", "908c2f8f-64bd-4059-a01a-921a7afbb715", "5ce8164d-0911-4d05-9245-bc9b172295b5", "37cbcaf0-d804-4776-ad68-2feba10f3938", "b909d248-018c-4776-b271-4b1f540fdd74", "b8d3468e-283a-4667-86e1-0f8bedfab78e", "c5fcb00a-6eb4-4d4c-859a-4a3784de5c9d", "dcf6129b-1983-4a3e-8bf7-e69fd5b31fa4", "37fd0930-5882-4d2d-b756-0ab51d75ad1e", "b9afd4c7-52be-4aaa-b13b-00bc21011cf7", "b9df7747-36c8-4bf6-bb13-7765cfd948a8", "4508be39-5204-452b-8afc-c6e118eb002b", "892a565d-0a86-4155-b3b5-90f2dcb226b1", "5e0946c2-0431-489e-8e0f-cb0e244428e3", "d7a17d53-ac6f-4157-85b2-13a16d469c5d", "52f8a8a4-84a3-4d15-9f5b-5b10da562090"], "allowedRatios": ["7f1c62d9-51d0-4452-bfce-dc59f5d46cd5", "d5f3c059-03e3-4ef3-afd8-b4d13315c60c", "ed36b158-80c9-4b92-ba96-269ae5b222b0", "399ab36b-9fd1-48fa-9218-22cafa88416b", "352eec85-52e8-455d-9b79-ea3e2351f894", "672aee1b-8d97-4b2f-a122-e0ca5cdfb7f3"], "configurerType": "single-canvas"}', 'active', 3, '2026-04-17 18:08:24.663+00', 'Single Canvas Print - Custom Photo Canvas | Photify', E'Create stunning wall art with our premium custom canvas prints, designed to transform your favorite photos into timeless décor. Printed on high-quality artist-grade canvas using advanced, fade-resistant inks, every detail is captured with exceptional clarity and vibrant color.\n\nOur gallery-wrapped canvases are hand-stretched over durable wooden frames, giving a clean, modern edge that looks beautiful in any space. Whether you''re decorating a living room, bedroom, kitchen, or office, these prints add a personal and stylish touch to your home.\n\nPerfect for wedding photos, family portraits, pet pictures, or travel memories, our canvas prints also make thoughtful gifts for birthdays, anniversaries, and special occasions.\n\nChoose from multiple sizes and square or landscape formats to suit your space. Each canvas arrives ready to hang, making it easy to create a professional gallery look in minutes.\n\nUpload your photo, customize your size, and bring your memories to life with a high-quality canvas print made to last.\n', '{"Custom canvas prints","Photo canvas prints","Personalized canvas wall art","Canvas photo printing","Custom photo gifts","Canvas wall decor","Gallery wrapped canvas","Photo to canvas print","High quality canvas prints","Family photo canvas"}', 'index,follow', 'https://photify.com/product/single-canvas', 'Single Canvas Print - Custom Photo Canvas | Photify', E'Turn your favorite memories into beautiful canvas prints. From family moments to pet photos, create timeless wall art that adds warmth and personality to any space. Upload your photo and bring it to life today.\n', 'https://images.unsplash.com/photo-1686644472082-75dd48820a5d?w=1200', '[]', '[{"icon": "check", "text": "Ready to Hang"}, {"icon": "sparkles", "text": "Real-life colours "}, {"icon": "zap", "text": "Super simple to create"}, {"icon": "badge-check", "text": "High-end quality"}]', '[{"label": "Product Type", "value": "Custom Photo Canvas Print"}, {"label": "Finish", "value": "Canvas Matt"}, {"label": "Frame Thickness", "value": "2 Inches"}, {"label": "Mounting", "value": "Ready to Hang"}, {"label": "Orientation", "value": "Square, Portrait, Landscape"}, {"label": "Usage", "value": "Home, Office, Gifts"}]', '[]', 4.9, 127, 1, 'https://mhlmbpnyckrqyznwmbwo.supabase.co/storage/v1/object/public/photify/featured-products/featured-00845beb-23c6-4d3b-8f55-a62eb956f182-1776446982573.png', 120.00) ON CONFLICT (id) DO NOTHING;
